// StarterSuggestions.tsx
interface Suggestion { label: string; prompt: string; }

export function StarterSuggestions({
  suggestions,
  onSelect,
}: {
  suggestions: Suggestion[];
  onSelect: (prompt: string) => void;
}) {
  return (
    <div className="flex flex-col items-center justify-center h-full gap-6">
      <p className="text-slate-400 text-lg">What would you like to do?</p>
      <div className="grid grid-cols-2 gap-3 max-w-lg w-full px-4">
        {suggestions.map(s => (
          <button
            key={s.label}
            onClick={() => onSelect(s.prompt)}
            className="text-left text-sm bg-slate-800 hover:bg-indigo-900/50 border border-slate-700
                       hover:border-indigo-600 rounded-xl p-4 text-slate-300 transition-colors"
          >
            <span className="text-indigo-400 mr-2">&#10022;</span>
            {s.label}
          </button>
        ))}
      </div>
    </div>
  );
}
