// FollowUpChips.tsx - rendered below the last assistant message
export function FollowUpChips({
  suggestions,
  onSelect,
  loading,
}: {
  suggestions: string[];
  onSelect: (s: string) => void;
  loading: boolean;
}) {
  if (loading) {
    return (
      <div className="flex gap-2 mt-2">
        {[80, 100, 90].map(w => (
          <div key={w} className="h-7 rounded-full bg-slate-700 animate-pulse" style={{ width: w }} />
        ))}
      </div>
    );
  }
  return (
    <div className="flex flex-wrap gap-2 mt-2">
      {suggestions.map(s => (
        <button
          key={s}
          onClick={() => onSelect(s)}
          className="text-xs bg-green-950 border border-green-800 text-green-300
                     hover:bg-green-900 rounded-full px-3 py-1 transition-colors"
        >
          {s}
        </button>
      ))}
    </div>
  );
}

// useSlashCommands.ts
export interface SlashCommand {
  name: string;
  description: string;
  template: string;  // cursor position marked as {|}
  icon: string;
}

export const SLASH_COMMANDS: SlashCommand[] = [
  { name: "search",    description: "Search the web",       template: "Search the web for {|}",    icon: "search" },
  { name: "summarise", description: "Summarise a URL",      template: "Summarise this URL: {|}",   icon: "doc"    },
  { name: "code",      description: "Write and run code",   template: "Write Python code that {|}",icon: "code"   },
  { name: "translate", description: "Translate text",       template: "Translate to {|}: ",        icon: "globe"  },
  { name: "compare",   description: "Compare two things",   template: "Compare {|} and ",          icon: "split"  },
  { name: "explain",   description: "Explain a concept",    template: "Explain {|} simply",        icon: "light"  },
];

export function useSlashCommands(draft: string) {
  const match = draft.match(/^\/([\w]*)$/);
  const query = match ? match[1].toLowerCase() : null;
  const visible = query !== null;
  const filtered = visible ? SLASH_COMMANDS.filter(c => c.name.startsWith(query)) : [];
  return { visible, filtered, query };
}

// SlashCommandMenu.tsx
import { useSlashCommands, SlashCommand } from "./useSlashCommands";

export function SlashCommandMenu({
  draft, onSelect,
}: { draft: string; onSelect: (template: string) => void; }) {
  const { visible, filtered } = useSlashCommands(draft);
  if (!visible || filtered.length === 0) return null;

  return (
    <div className="absolute bottom-full left-0 right-0 mb-1 bg-slate-800 border border-slate-600
                    rounded-xl shadow-xl overflow-hidden z-10">
      {filtered.map((cmd, i) => (
        <button
          key={cmd.name}
          onClick={() => onSelect(cmd.template.replace("{|}", ""))}
          className={`w-full flex items-center gap-3 px-4 py-2.5 text-left text-sm
                      hover:bg-slate-700 ${i === 0 ? "bg-slate-700" : ""}`}
        >
          <span className="text-indigo-300 font-mono">/{cmd.name}</span>
          <span className="text-slate-400 text-xs ml-2">{cmd.description}</span>
        </button>
      ))}
    </div>
  );
}

// MessageActions.tsx - hover action bar for each message
export function MessageActions({
  role, content, onRetry, onEdit, onFeedback,
}: {
  role: "user" | "assistant";
  content: string;
  onRetry?: () => void;
  onEdit?: (newContent: string) => void;
  onFeedback?: (val: "up" | "down") => void;
}) {
  const copy = () => navigator.clipboard.writeText(content);

  return (
    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity
                    bg-slate-800 border border-slate-700 rounded-lg px-2 py-1 text-xs text-slate-400">
      <Btn icon="copy"  label="Copy"  onClick={copy} />
      {role === "assistant" && onRetry && <Btn icon="retry" label="Retry"  onClick={onRetry} />}
      {role === "user"      && onEdit  && <Btn icon="edit"  label="Edit"   onClick={() => onEdit(content)} />}
      {role === "assistant" && onFeedback && (
        <>
          <Btn icon="up"   label="Good" onClick={() => onFeedback("up")} />
          <Btn icon="down" label="Bad"  onClick={() => onFeedback("down")} />
        </>
      )}
    </div>
  );
}

