// CodeBlock.tsx - renders fenced code with copy/run action bar
import { useState } from "react";

export function CodeBlock({ language, code }: { language: string; code: string }) {
  const [copied, setCopied] = useState(false);
  const [output, setOutput]  = useState<string | null>(null);

  const copy = async () => {
    await navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  };

  const run = async () => {
    const res = await fetch("/execute", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ language, code }),
    });
    const { stdout, stderr } = await res.json();
    setOutput(stdout || stderr);
  };

  return (
    <div className="my-3 rounded-xl overflow-hidden border border-slate-700">
      <div className="flex items-center justify-between bg-slate-900 px-3 py-1.5">
        <span className="text-xs text-slate-500 font-mono">{language || "text"}</span>
        <div className="flex gap-2">
          {language === "python" && (
            <button onClick={run} className="text-xs text-green-400 hover:text-green-200">Run</button>
          )}
          <button onClick={copy} className="text-xs text-slate-400 hover:text-slate-200">
            {copied ? "Copied" : "Copy"}
          </button>
        </div>
      </div>
      <pre className="bg-slate-950 p-4 overflow-x-auto text-sm text-slate-300"><code>{code}</code></pre>
      {output !== null && (
        <div className="bg-slate-900 border-t border-slate-700 p-3 font-mono text-xs text-green-300">
          {output}
        </div>
      )}
    </div>
  );
}

// ToolSelector.tsx
const AVAILABLE_TOOLS = [
  { id: "web_search",       label: "Web search",       icon: "search" },
  { id: "code_interpreter", label: "Code interpreter",  icon: "code"   },
  { id: "file_upload",      label: "File upload",       icon: "clip"   },
  { id: "image_gen",        label: "Image generation",  icon: "image"  },
];

export function ToolSelector({
  active, onChange,
}: { active: Set<string>; onChange: (next: Set<string>) => void; }) {
  const toggle = (id: string) => {
    const next = new Set(active);
    next.has(id) ? next.delete(id) : next.add(id);
    onChange(next);
  };
  return (
    <div className="flex flex-wrap gap-2 px-4 pb-2">
      {AVAILABLE_TOOLS.map(t => (
        <button
          key={t.id}
          onClick={() => toggle(t.id)}
          className={`flex items-center gap-1 text-xs rounded-full px-3 py-1 border transition-colors
            ${active.has(t.id)
              ? "bg-violet-900/60 border-violet-600 text-violet-300"
              : "bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-400"}`}
        >
          {t.label}
        </button>
      ))}
    </div>
  );
}
