// useAgentPreferences.ts - persist model and active tools in localStorage
import { useState, useEffect } from "react";

interface AgentPrefs { activeTools: string[]; model: string; }
const DEFAULTS: AgentPrefs = { activeTools: ["web_search"], model: "claude-opus-4-8" };

export function useAgentPreferences() {
  const [prefs, setPrefs] = useState<AgentPrefs>(() => {
    try {
      const stored = localStorage.getItem("agent-prefs");
      return stored ? { ...DEFAULTS, ...JSON.parse(stored) } : DEFAULTS;
    } catch {
      return DEFAULTS;
    }
  });

  useEffect(() => {
    localStorage.setItem("agent-prefs", JSON.stringify(prefs));
  }, [prefs]);

  const setModel   = (model: string) => setPrefs(p => ({ ...p, model }));
  const toggleTool = (id: string) =>
    setPrefs(p => ({
      ...p,
      activeTools: p.activeTools.includes(id)
        ? p.activeTools.filter(t => t !== id)
        : [...p.activeTools, id],
    }));

  return { prefs, setModel, toggleTool };
}

// useSlashCommands.test.ts
import { useSlashCommands, SLASH_COMMANDS } from "./useSlashCommands";

test("returns visible=true and filtered commands for /se", () => {
  const { visible, filtered } = useSlashCommands("/se");
  expect(visible).toBe(true);
  expect(filtered.some(c => c.name === "search")).toBe(true);
});

test("returns visible=false for normal text", () => {
  const { visible } = useSlashCommands("hello world");
  expect(visible).toBe(false);
});

test("returns all commands for bare /", () => {
  const { visible, filtered } = useSlashCommands("/");
  expect(visible).toBe(true);
  expect(filtered.length).toBe(SLASH_COMMANDS.length);
});
